function renderReleaseRuntimeJobCard(job = {}, bucket = 'recent') {
  const jobId = String(job.id || '').trim();
  const requestId = String(job.requestId || '').trim();
  const status = String(job.status || (bucket === 'active' ? 'active' : 'unknown')).trim();
  const scope = String(job.scope || '').trim();
  const durationLabel = bucket === 'active'
    ? 'running'
    : formatDurationMs(job.durationMs);
  const timestamp = bucket === 'active'
    ? job.startedAt
    : job.endedAt || job.startedAt;
  return `
    <article class="release-snapshot-card" data-release-runtime-job-id="${escapeHtml(jobId)}">
      <div class="release-provider-meta">
        <div>
          <div class="item-title">${escapeHtml(getRuntimeJobKindLabel(job.kind))}</div>
          <div class="item-meta">${escapeHtml(scope ? getReleaseActionScopeLabel(scope) : 'runtime flow')}${requestId ? ` В· request ${escapeHtml(requestId.slice(0, 12))}` : ''}</div>
        </div>
        <div class="release-history-actions">
          <span class="mini-badge ${getReleaseStatusBadge(status)}">${escapeHtml(status || 'unknown')}</span>
          <span class="mini-badge status-pending">${escapeHtml(durationLabel)}</span>
        </div>
      </div>
      <div class="item-meta">${escapeHtml(job.summary || (bucket === 'active' ? 'runtime job is currently active.' : 'runtime job summaryк°Җ м—ҶмҠөлӢҲлӢӨ.'))}</div>
      <div class="release-meta release-meta-secondary">
        <span class="item-meta">${escapeHtml(bucket === 'active' ? 'started' : 'finished')} ${escapeHtml(formatDate(timestamp))}</span>
        ${jobId ? `<span class="item-meta mono">${escapeHtml(jobId.slice(0, 24))}</span>` : ''}
        ${job.source ? `<span class="item-meta">${escapeHtml(job.source)}</span>` : ''}
      </div>
    </article>
  `;
}

function isReleaseAttentionOutcome(outcome = '') {
  const normalized = String(outcome || '').trim().toLowerCase();
  return normalized === 'blocked' || normalized === 'failed' || normalized === 'confirmation-required';
}

function matchesReleaseActionRecommendation(item, historyItem, providerReadiness = []) {
  const action = String(item?.action || '').trim();
  const actionProvider = String(item?.actionProvider || '').trim();
  const providerFromEnv = String(
    providerReadiness.find((entry) => String(entry.envKey || '').trim() === String(item?.envKey || '').trim())?.provider || '',
  ).trim();
  const provider = actionProvider || providerFromEnv;
  const historyAction = String(historyItem?.action || '').trim();
  const historyScope = String(historyItem?.scope || '').trim();
  const historyProvider = String(historyItem?.provider || '').trim();

  if (action === 'regenerate-release-surface') {
    return historyScope === 'current-surface' && (historyAction === 'refresh' || historyAction === 'refresh-preflight');
  }

  if (action === 'archive-release-snapshot') {
    return historyScope === 'snapshot' && (historyAction === 'snapshot' || historyAction === 'snapshot-preflight');
  }

  if (action === 'run-release-preflight' && provider) {
    return historyAction === 'provider-preflight' && historyProvider === provider;
  }

  if (!action && provider) {
    return historyProvider === provider;
  }

  return false;
}

function getRecommendationHistoryContext(item, releaseActionHistory = [], providerReadiness = []) {
  if (!Array.isArray(releaseActionHistory) || !releaseActionHistory.length) {
    return {
      attentionCount: 0,
      latestAction: null,
      latestAttentionAction: null,
      matchCount: 0,
    };
  }

  const matches = releaseActionHistory.filter((historyItem) => matchesReleaseActionRecommendation(item, historyItem, providerReadiness));
  const attentionMatches = matches.filter((historyItem) => isReleaseAttentionOutcome(historyItem?.outcome));
  return {
    attentionCount: attentionMatches.length,
    latestAction: matches[0] || null,
    latestAttentionAction: attentionMatches[0] || null,
    matchCount: matches.length,
  };
}

function getRecommendationProviderEntry(item, providerReadiness = []) {
  const actionProvider = String(item?.actionProvider || '').trim();
  const envKey = String(item?.envKey || '').trim();
  return providerReadiness.find((entry) => {
    const entryProvider = String(entry?.provider || '').trim();
    const entryEnvKey = String(entry?.envKey || '').trim();
    return (actionProvider && entryProvider === actionProvider) || (envKey && entryEnvKey === envKey);
  });
}

function getRecommendationCommandContext(item, providerReadiness = []) {
  const action = String(item?.action || '').trim();
  const explicitCommand = String(item?.command || '').trim();
  const envKey = String(item?.envKey || '').trim();
  const providerEntry = getRecommendationProviderEntry(item, providerReadiness);

  if (explicitCommand) {
    return {
      command: explicitCommand,
      label: item?.label ? `${item.label} лӘ…л №` : 'к¶ҢмһҘ м•Ўм…ҳ лӘ…л №',
      buttonLabel: action === 'run-release-preflight' ? 'preflight лӘ…л № ліөмӮ¬' : 'live лӘ…л № ліөмӮ¬',
    };
  }

  if (action === 'run-release-preflight') {
    if (!providerEntry) {
      return null;
    }
    return {
      command: String(providerEntry.preflightCommand || '').trim(),
      label: `${providerEntry.label} preflight лӘ…л №`,
      buttonLabel: 'preflight лӘ…л № ліөмӮ¬',
    };
  }

  if (envKey) {
    if (!providerEntry) {
      return null;
    }
    return {
      command: providerEntry.ready
        ? String(providerEntry.command || '').trim()
        : `export ${providerEntry.envKey}="..." && ${providerEntry.command}`,
      label: `${providerEntry.label} live лӘ…л №`,
      buttonLabel: 'live лӘ…л № ліөмӮ¬',
    };
  }

  return null;
}

function getProviderLiveCommand(providerEntry = {}, preflight = null) {
  if (providerEntry?.ready) {
    return String(providerEntry.command || '').trim();
  }

  return String(preflight?.missingEnvCommand || '').trim()
    || `export ${providerEntry.envKey}="..." && ${providerEntry.command}`;
}

function isRecommendationFlowActive({ attentionAction = null, latestAction = null }, {
  focusedHistoryId = '',
  historyFilterOutcome = '',
  historyFilterProvider = '',
  historyFilterScope = '',
} = {}) {
  const historyId = String(latestAction?.id || '').trim();
  const scope = String(latestAction?.scope || '').trim();
  const provider = String(latestAction?.provider || '').trim();
  const attentionHistoryId = String(attentionAction?.id || '').trim();
  const attentionScope = String(attentionAction?.scope || '').trim() || scope;
  const attentionProvider = String(attentionAction?.provider || '').trim() || provider;

  return {
    attentionFlowActive:
      Boolean(attentionHistoryId)
      && focusedHistoryId === attentionHistoryId
      && historyFilterOutcome === 'attention'
      && historyFilterScope === attentionScope
      && historyFilterProvider === attentionProvider,
    sameFlowActive:
      Boolean(historyId)
      && focusedHistoryId === historyId
      && historyFilterOutcome === ''
      && historyFilterScope === scope
      && historyFilterProvider === provider,
  };
}

function getReleaseCurrentOpenBlockerActions(releaseStatus = state.releaseStatus) {
  const releaseReadiness = releaseStatus?.releaseReadiness || {};
  const currentOpenBlockers = Array.isArray(releaseReadiness.currentOpenBlockers)
    ? releaseReadiness.currentOpenBlockers
    : [];

  return Array.isArray(releaseReadiness.currentOpenBlockerActions)
    ? releaseReadiness.currentOpenBlockerActions
    : currentOpenBlockers.map((item, index) => ({
        blocker: item,
        category: 'release-readiness',
        commands: [],
        evidenceDocs: [],
        id: `current-open-blocker-${index + 1}`,
        nextEvidence: '',
        owner: 'release-owner',
        status: 'blocked',
        stopReason: item,
      }));
}

function getReleaseCurrentOpenBlockerAction(blockerId = '') {
  const normalizedBlockerId = String(blockerId || '').trim();
  if (!normalizedBlockerId) {
    return null;
  }
  return getReleaseCurrentOpenBlockerActions().find((item) => String(item.id || '').trim() === normalizedBlockerId) || null;
}

function isReleaseBlockerActionVisibleForFilter(
  blockerAction = null,
  {
    category = state.releaseBlockerCategoryFilter,
    includeShared = state.releaseBlockerIncludeSharedProviderOperations,
    owner = state.releaseBlockerOwnerFilter,
    provider = state.releaseBlockerProviderFilter,
  } = {},
) {
  if (!blockerAction) {
    return false;
  }
  if (includeShared === false && isReleaseSharedProviderBlockerAction(blockerAction)) {
    return false;
  }
  const normalizedCategory = String(category || '').trim();
  const normalizedOwner = String(owner || '').trim();
  const normalizedProvider = String(provider || '').trim();
  const actionCategory = String(blockerAction.category || '').trim();
  const actionOwner = String(blockerAction.owner || '').trim();
  return (!normalizedCategory || actionCategory === normalizedCategory)
    && (!normalizedOwner || actionOwner === normalizedOwner)
    && (
      !normalizedProvider
      || isReleaseSharedProviderBlockerAction(blockerAction)
      || doesReleaseBlockerActionMatchProvider(blockerAction, normalizedProvider)
    );
}

function isReleaseBlockerActionVisibleForCopyScope(
  blockerAction = null,
  {
    category = state.releaseBlockerCategoryFilter,
    includeShared = state.releaseBlockerIncludeSharedProviderOperations,
    owner = state.releaseBlockerOwnerFilter,
    provider = state.releaseBlockerProviderFilter,
  } = {},
) {
  return isReleaseBlockerActionVisibleForFilter(blockerAction, {
    category,
    includeShared,
    owner,
    provider,
  });
}

function getFilteredReleaseCurrentOpenBlockerActions(releaseStatus = state.releaseStatus) {
  return getReleaseCurrentOpenBlockerActions(releaseStatus).filter((item) =>
    isReleaseBlockerActionVisibleForFilter(item),
  );
}

function getAbsoluteReleaseUrl(href = '') {
  const normalizedHref = String(href || '').trim();
  if (!normalizedHref) {
    return '';
  }
  if (normalizedHref.startsWith('http://') || normalizedHref.startsWith('https://')) {
    return normalizedHref;
  }
  return `${window.location.origin}${normalizedHref.startsWith('/') ? normalizedHref : `/${normalizedHref}`}`;
}

function getReleaseCountRecordEntries(record = {}) {
  if (!record || typeof record !== 'object') {
    return [];
  }
  return Object.entries(record)
    .map(([key, value]) => [String(key || '').trim(), Number(value || 0)])
    .filter(([key, value]) => Boolean(key) && value > 0)
    .sort(([leftKey, leftValue], [rightKey, rightValue]) => rightValue - leftValue || leftKey.localeCompare(rightKey));
}

function buildReleaseBlockerSliceUrl({
  category = state.releaseBlockerCategoryFilter,
  includeShared = state.releaseBlockerIncludeSharedProviderOperations,
  owner = state.releaseBlockerOwnerFilter,
  provider = state.releaseBlockerProviderFilter,
} = {}) {
  const normalizedCategory = String(category || '').trim();
  const normalizedOwner = String(owner || '').trim();
  const normalizedProvider = String(provider || '').trim();
  return `${window.location.origin}${buildUiStateUrl({
    detailTab: 'release',
    releaseBlockerCategoryFilter: normalizedCategory,
    releaseBlockerIncludeSharedProviderOperations: includeShared !== false,
    releaseBlockerOwnerFilter: normalizedOwner,
    releaseBlockerProviderFilter: normalizedProvider,
    releaseFocusedBlockerId: '',
    releaseFocusedProductionBlockerIndex: '',
    releaseFocusedProvider: normalizedProvider,
    releaseFocusedHistoryId: '',
    releaseHistoryOutcome: '',
    releaseHistoryProvider: '',
    releaseHistoryScope: '',
  })}`;
}

function buildReleaseBlockerApiUrl({
  category = state.releaseBlockerCategoryFilter,
  includeShared = true,
  owner = state.releaseBlockerOwnerFilter,
  provider = state.releaseBlockerProviderFilter,
} = {}) {
  const normalizedCategory = String(category || '').trim();
  const shouldIncludeShared = includeShared !== false;
  const normalizedOwner = String(owner || '').trim();
  const normalizedProvider = String(provider || '').trim();
  const params = new URLSearchParams();
  if (normalizedCategory) {
    params.set('category', normalizedCategory);
  }
  if (normalizedOwner) {
    params.set('owner', normalizedOwner);
  }
  if (normalizedProvider) {
    params.set('provider', normalizedProvider);
  }
  if (!shouldIncludeShared) {
    params.set('includeShared', 'false');
  }
  const query = params.toString();
  return getAbsoluteReleaseUrl(`/api/execution-v1/release-blockers${query ? `?${query}` : ''}`);
}

function getReleaseProductionBlockers(releaseStatus = state.releaseStatus) {
  const releaseReadiness = releaseStatus?.releaseReadiness || {};
  return Array.isArray(releaseReadiness.productionBlockers)
    ? releaseReadiness.productionBlockers
      .map((item) => String(item || '').trim())
      .filter(Boolean)
    : [];
}

function getValidReleaseProductionBlockerIndex(value, releaseStatus = state.releaseStatus) {
  const normalizedIndex = normalizeReleaseProductionBlockerStateIndex(value);
  if (normalizedIndex === '') {
    return '';
  }
  const productionBlockers = getReleaseProductionBlockers(releaseStatus);
  const index = Number(normalizedIndex);
  return index >= 0 && index < productionBlockers.length ? String(index) : '';
}

function getReleaseProductionBlockerVerificationCommands() {
  return [
    {
      command: 'npm run smoke:production-readiness-gate',
      label: 'Production readiness gate',
    },
    {
      command: 'npm run smoke:release-artifact-hygiene',
      label: 'Release artifact hygiene',
    },
    {
      command: 'npm run smoke:execution-v1-status',
      label: 'Execution v1 status',
    },
  ];
}

function buildReleaseProductionBlockerSummaryText({
  productionBlockers = getReleaseProductionBlockers(),
  releaseStatus = state.releaseStatus,
} = {}) {
  const blockers = Array.isArray(productionBlockers)
    ? productionBlockers.map((item) => String(item || '').trim()).filter(Boolean)
    : [];
  if (!blockers.length) {
    return '';
  }

  const summary = releaseStatus?.summary || {};
  const releaseReadiness = releaseStatus?.releaseReadiness || {};
  const productionReadyStatus = String(
    summary.productionReadyStatus || releaseReadiness.productionReadyStatus || 'not tracked',
  ).trim();
  const productionReadyStopReason = String(
    summary.productionReadyStopReason || releaseReadiness.productionReadyStopReason || blockers[0] || '',
  ).trim();
  const releaseLabel = String(releaseReadiness.releaseLabel || summary.releaseLabel || '').trim();
  const releaseLink = `${window.location.origin}${buildUiStateUrl({
    detailTab: 'release',
    releaseBlockerCategoryFilter: '',
    releaseBlockerOwnerFilter: '',
    releaseBlockerProviderFilter: '',
    releaseFocusedBlockerId: '',
    releaseFocusedProductionBlockerIndex: '',
    releaseFocusedProvider: '',
    releaseFocusedHistoryId: '',
    releaseHistoryOutcome: '',
    releaseHistoryProvider: '',
    releaseHistoryScope: '',
  })}`;
  const releaseReadinessDocLink = getAbsoluteReleaseUrl('/api/execution-v1/release-doc?path=docs%2Frelease-readiness-v1.md');
  const lines = [
    'Production-ready blocker summary',
    `- productionReadyStatus: ${productionReadyStatus}`,
    `- productionReadyBlocked: ${String(Boolean(summary.productionReadyBlocked ?? releaseReadiness.productionReadyBlocked ?? true))}`,
    `- productionBlockerCount: ${blockers.length}`,
    `- releaseLabel: ${releaseLabel || 'not tracked'}`,
    `- stopReason: ${productionReadyStopReason || 'not recorded'}`,
    `- releaseLink: ${releaseLink}`,
    `- releaseReadinessDoc: ${releaseReadinessDocLink}`,
    '',
    'Commands:',
    '- Production readiness gate: npm run smoke:production-readiness-gate',
    '- Release artifact hygiene: npm run smoke:release-artifact-hygiene',
    '- Execution v1 status: npm run smoke:execution-v1-status',
    '',
    'Blockers:',
    ...blockers.map((item, index) => `${index + 1}. ${item}`),
  ];

  return `${lines.join('\n')}\n`;
}

function buildReleaseProductionBlockerHandoffText({
  blockerIndex = 0,
  productionBlockers = getReleaseProductionBlockers(),
  releaseStatus = state.releaseStatus,
} = {}) {
  const blockers = Array.isArray(productionBlockers)
    ? productionBlockers.map((item) => String(item || '').trim()).filter(Boolean)
    : [];
  const normalizedIndex = Number.isFinite(Number(blockerIndex)) ? Number(blockerIndex) : 0;
  const blocker = blockers[normalizedIndex] || '';
  if (!blocker) {
    return '';
  }

  const summary = releaseStatus?.summary || {};
  const releaseReadiness = releaseStatus?.releaseReadiness || {};
  const productionReadyStatus = String(
    summary.productionReadyStatus || releaseReadiness.productionReadyStatus || 'not tracked',
  ).trim();
  const releaseLabel = String(releaseReadiness.releaseLabel || summary.releaseLabel || '').trim();
  const releaseFocusedProductionBlockerIndex = getValidReleaseProductionBlockerIndex(
    normalizedIndex,
    releaseStatus,
  );
  const releaseLink = `${window.location.origin}${buildUiStateUrl({
    detailTab: 'release',
    releaseBlockerCategoryFilter: '',
    releaseBlockerOwnerFilter: '',
    releaseBlockerProviderFilter: '',
    releaseFocusedBlockerId: '',
    releaseFocusedProductionBlockerIndex,
    releaseFocusedProvider: '',
    releaseFocusedHistoryId: '',
    releaseHistoryOutcome: '',
    releaseHistoryProvider: '',
    releaseHistoryScope: '',
  })}`;
  const releaseReadinessDocLink = getAbsoluteReleaseUrl('/api/execution-v1/release-doc?path=docs%2Frelease-readiness-v1.md');
  const lines = [
    'Production-ready blocker handoff',
    `- blockerIndex: ${normalizedIndex + 1}/${blockers.length}`,
    `- productionReadyStatus: ${productionReadyStatus}`,
    `- productionReadyBlocked: ${String(Boolean(summary.productionReadyBlocked ?? releaseReadiness.productionReadyBlocked ?? true))}`,
    `- releaseLabel: ${releaseLabel || 'not tracked'}`,
    `- blocker: ${blocker}`,
    `- releaseLink: ${releaseLink}`,
    `- releaseReadinessDoc: ${releaseReadinessDocLink}`,
    '',
    'Commands:',
    '- Production readiness gate: npm run smoke:production-readiness-gate',
    '- Release artifact hygiene: npm run smoke:release-artifact-hygiene',
    '- Execution v1 status: npm run smoke:execution-v1-status',
  ];

  return `${lines.join('\n')}\n`;
}

function buildReleaseProductionBlockerCommandText({
  blockerIndex = 0,
  productionBlockers = getReleaseProductionBlockers(),
  releaseStatus = state.releaseStatus,
} = {}) {
  const blockers = Array.isArray(productionBlockers)
    ? productionBlockers.map((item) => String(item || '').trim()).filter(Boolean)
    : [];
  const normalizedIndex = Number.isFinite(Number(blockerIndex)) ? Number(blockerIndex) : 0;
  const blocker = blockers[normalizedIndex] || '';
  if (!blocker) {
    return '';
  }

  const releaseFocusedProductionBlockerIndex = getValidReleaseProductionBlockerIndex(
    normalizedIndex,
    releaseStatus,
  );
  const releaseLink = `${window.location.origin}${buildUiStateUrl({
    detailTab: 'release',
    releaseBlockerCategoryFilter: '',
    releaseBlockerOwnerFilter: '',
    releaseBlockerProviderFilter: '',
    releaseFocusedBlockerId: '',
    releaseFocusedProductionBlockerIndex,
    releaseFocusedProvider: '',
    releaseFocusedHistoryId: '',
    releaseHistoryOutcome: '',
    releaseHistoryProvider: '',
    releaseHistoryScope: '',
  })}`;
  const releaseReadinessDocLink = getAbsoluteReleaseUrl('/api/execution-v1/release-doc?path=docs%2Frelease-readiness-v1.md');
  const commands = getReleaseProductionBlockerVerificationCommands();
  const lines = [
    'Production-ready blocker verification commands',
    `- blockerIndex: ${normalizedIndex + 1}/${blockers.length}`,
    `- blocker: ${blocker}`,
    `- releaseLink: ${releaseLink}`,
    `- releaseReadinessDoc: ${releaseReadinessDocLink}`,
    '',
    'Commands:',
    ...commands.map((item) => `- ${item.label}: ${item.command}`),
  ];

  return `${lines.join('\n')}\n`;
}

function buildReleaseProductionBlockerPackageText({
  blockerIndex = 0,
  productionBlockers = getReleaseProductionBlockers(),
  releaseStatus = state.releaseStatus,
} = {}) {
  const blockers = Array.isArray(productionBlockers)
    ? productionBlockers.map((item) => String(item || '').trim()).filter(Boolean)
    : [];
  const normalizedIndex = Number.isFinite(Number(blockerIndex)) ? Number(blockerIndex) : 0;
  const blocker = blockers[normalizedIndex] || '';
  if (!blocker) {
    return '';
  }

  const releaseFocusedProductionBlockerIndex = getValidReleaseProductionBlockerIndex(
    normalizedIndex,
    releaseStatus,
  );
  const releaseLink = `${window.location.origin}${buildUiStateUrl({
    detailTab: 'release',
    releaseBlockerCategoryFilter: '',
    releaseBlockerOwnerFilter: '',
    releaseBlockerProviderFilter: '',
    releaseFocusedBlockerId: '',
    releaseFocusedProductionBlockerIndex,
    releaseFocusedProvider: '',
    releaseFocusedHistoryId: '',
    releaseHistoryOutcome: '',
    releaseHistoryProvider: '',
    releaseHistoryScope: '',
  })}`;
  const releaseReadinessDocLink = getAbsoluteReleaseUrl('/api/execution-v1/release-doc?path=docs%2Frelease-readiness-v1.md');
  const evidenceSection = [
    'Production-ready blocker evidence',
    `- blockerIndex: ${normalizedIndex + 1}/${blockers.length}`,
    `- blocker: ${blocker}`,
    `- releaseLink: ${releaseLink}`,
    `- evidenceDocCount: 1`,
    '',
    'Evidence docs:',
    '1. Release readiness v1',
    '   - path: docs/release-readiness-v1.md',
    `   - link: ${releaseReadinessDocLink}`,
    '   - availability: available',
    '   - source: Production Ready blocker list',
  ].join('\n');
  const sections = [
    buildReleaseProductionBlockerHandoffText({
      blockerIndex: normalizedIndex,
      productionBlockers: blockers,
      releaseStatus,
    }),
    buildReleaseProductionBlockerCommandText({
      blockerIndex: normalizedIndex,
      productionBlockers: blockers,
      releaseStatus,
    }),
    evidenceSection,
  ]
    .map((section) => String(section || '').trim())
    .filter(Boolean);

  if (!sections.length) {
    return '';
  }

  return `Production-ready blocker package\n\n${sections.join('\n\n')}\n`;
}

function getReleaseProviderReadinessEntries({
  provider = '',
  releaseStatus = state.releaseStatus,
} = {}) {
  const providerReadiness = Array.isArray(releaseStatus?.providerReadiness)
    ? releaseStatus.providerReadiness
    : [];
  const normalizedProvider = String(provider || '').trim();
  return providerReadiness.filter((item) => {
    const itemProvider = String(item?.provider || '').trim();
    return itemProvider && (!normalizedProvider || itemProvider === normalizedProvider);
  });
}

function getReleaseProviderClosureSummary(providerReadinessEntry = {}, providerBlockerActions = []) {
  const summary = providerReadinessEntry?.blockerClosureVerification || {};
  const blockerActions = Array.isArray(providerBlockerActions) ? providerBlockerActions : [];
  const fallbackClosureIds = blockerActions
    .map((action) => String(getReleaseBlockerClosureVerification(action).id || '').trim())
    .filter(Boolean);
  const fallbackCommands = blockerActions.flatMap((action) => getReleaseBlockerRequiredCommands(action));
  const fallbackEvidenceDocs = new Set(
    blockerActions
      .flatMap((action) => getReleaseBlockerRequiredEvidenceDocs(action))
      .map((doc) => String(doc?.href || doc?.path || doc?.label || '').trim())
      .filter(Boolean),
  );
  const fallbackRequiredProofs = new Set(blockerActions.flatMap((action) => getReleaseBlockerRequiredProofs(action)));
  const productionReadyBlockedCount = Number.isFinite(Number(summary.productionReadyBlockedCount))
    ? Number(summary.productionReadyBlockedCount)
    : blockerActions.filter((action) =>
      getReleaseBlockerClosureVerification(action).productionReadyClaimAllowed === false,
    ).length;
  const targetBoundaryRequiredCount = Number.isFinite(Number(summary.targetBoundaryRequiredCount))
    ? Number(summary.targetBoundaryRequiredCount)
    : blockerActions.filter((action) =>
      getReleaseBlockerClosureVerification(action).targetBoundaryRequired === true,
    ).length;

  return {
    closureVerificationCount: Number.isFinite(Number(summary.closureVerificationCount))
      ? Number(summary.closureVerificationCount)
      : fallbackClosureIds.length,
    commandCount: Number.isFinite(Number(summary.commandCount))
      ? Number(summary.commandCount)
      : fallbackCommands.length,
    evidenceDocCount: Number.isFinite(Number(summary.evidenceDocCount))
      ? Number(summary.evidenceDocCount)
      : fallbackEvidenceDocs.size,
    productionReadyBlockedCount,
    productionReadyClaimAllowed: summary.productionReadyClaimAllowed === true
      && productionReadyBlockedCount === 0,
    requiredProofCount: Number.isFinite(Number(summary.requiredProofCount))
      ? Number(summary.requiredProofCount)
      : fallbackRequiredProofs.size,
    targetBoundaryRequiredCount,
  };
}

function getReleaseProviderBlockerNeedles(provider = '') {
  const normalizedProvider = String(provider || '').trim();
  const providerNeedles = {
    anthropic: ['anthropic', 'anthropic_api_key', 'target-anthropic-provider-account'],
    hermes: ['hermes', 'hermes_provider_model', 'target-hermes-provider-architecture'],
    local: ['local provider', 'local_provider_model', 'local_provider_base_url', 'target-local-provider-architecture'],
    openai: ['openai', 'openai_api_key', 'target-openai-provider-account'],
  };
  return providerNeedles[normalizedProvider] || (normalizedProvider ? [normalizedProvider] : []);
}

function getReleaseBlockerActionSearchText(blockerAction = null) {
  const commands = Array.isArray(blockerAction?.commands) ? blockerAction.commands : [];
  const evidenceDocs = Array.isArray(blockerAction?.evidenceDocs) ? blockerAction.evidenceDocs : [];
  return [
    blockerAction?.blocker,
    blockerAction?.category,
    blockerAction?.id,
    blockerAction?.nextEvidence,
    blockerAction?.owner,
    blockerAction?.provider,
    blockerAction?.status,
    blockerAction?.stopReason,
    ...commands.flatMap((command) => [command?.command, command?.kind, command?.label]),
    ...evidenceDocs.flatMap((doc) => [doc?.href, doc?.label, doc?.path]),
  ]
    .map((item) => String(item || '').toLowerCase())
    .filter(Boolean)
    .join(' ');
}

function doesReleaseBlockerActionMatchProvider(blockerAction = null, provider = '') {
  const normalizedProvider = String(provider || '').trim();
  if (!blockerAction || !normalizedProvider) {
    return false;
  }
  if (String(blockerAction.provider || '').trim() === normalizedProvider) {
    return true;
  }

  const searchText = getReleaseBlockerActionSearchText(blockerAction);
  return getReleaseProviderBlockerNeedles(normalizedProvider).some((needle) =>
    searchText.includes(String(needle || '').toLowerCase()),
  );
}

function isReleaseSharedProviderBlockerAction(blockerAction = null) {
  return String(blockerAction?.category || '').trim() === 'provider-operations';
}

function getReleaseProviderBlockerActions({
  provider = '',
  releaseStatus = state.releaseStatus,
} = {}) {
  const normalizedProvider = String(provider || '').trim();
  if (!normalizedProvider) {
    return [];
  }

  const blockerActions = getReleaseCurrentOpenBlockerActions(releaseStatus);
  const hasExplicitProviderMapping = blockerActions.some((item) => String(item?.provider || '').trim());
  return blockerActions.filter((item) => {
    if (String(item?.provider || '').trim() === normalizedProvider) {
      return true;
    }
    if (isReleaseSharedProviderBlockerAction(item)) {
      return true;
    }
    if (hasExplicitProviderMapping) {
      return false;
    }
    return doesReleaseBlockerActionMatchProvider(item, normalizedProvider);
  });
}

function getUniqueReleaseProviderBlockerActions(blockerActions = []) {
  const seen = new Set();
  return (Array.isArray(blockerActions) ? blockerActions : []).filter((item, index) => {
    const actionId = String(item?.id || '').trim() || `provider-blocker-${index}`;
    if (seen.has(actionId)) {
      return false;
    }
    seen.add(actionId);
    return true;
  });
}

function buildReleaseProviderBlockerPackageLines(blockerActions = []) {
  const actions = getUniqueReleaseProviderBlockerActions(blockerActions);
  if (!actions.length) {
    return ['- none'];
  }

  return actions.map((action, index) => {
    const actionId = String(action.id || '').trim();
    const actionProvider = String(action.provider || '').trim();
    const closureVerification = getReleaseBlockerClosureVerification(action);
    const requiredProofs = getReleaseBlockerRequiredProofs(action);
    const releaseLink = `${window.location.origin}${buildUiStateUrl({
      detailTab: 'release',
      releaseBlockerCategoryFilter: '',
      releaseBlockerOwnerFilter: '',
      releaseBlockerProviderFilter: '',
      releaseFocusedBlockerId: actionId,
      releaseFocusedProductionBlockerIndex: '',
      releaseFocusedProvider: actionProvider,
      releaseFocusedHistoryId: '',
      releaseHistoryOutcome: '',
      releaseHistoryProvider: '',
      releaseHistoryScope: '',
    })}`;
    const commands = Array.isArray(action.commands) ? action.commands : [];
    const evidenceDocs = Array.isArray(action.evidenceDocs) ? action.evidenceDocs : [];
    return [
      `${index + 1}. ${String(action.blocker || action.stopReason || 'provider blocker').trim()}`,
      `   - id: ${actionId || 'not recorded'}`,
      `   - provider: ${actionProvider || 'inferred from blocker evidence'}`,
      `   - category: ${String(action.category || 'stop-condition').trim()}`,
      `   - owner: ${String(action.owner || 'release-owner').trim()}`,
      `   - status: ${String(action.status || 'blocked').trim()}`,
      `   - sharedProviderBlocker: ${String(isReleaseSharedProviderBlockerAction(action))}`,
      `   - closureVerification: ${String(closureVerification.id || 'not provided').trim()}`,
      `   - targetBoundaryRequired: ${String(Boolean(closureVerification.targetBoundaryRequired ?? true))}`,
      `   - productionReadyClaimAllowed: ${String(Boolean(closureVerification.productionReadyClaimAllowed))}`,
      `   - stopReason: ${String(action.stopReason || action.blocker || '').trim() || 'not recorded'}`,
      `   - nextEvidence: ${String(action.nextEvidence || '').trim() || 'not recorded'}`,
      `   - releaseLink: ${releaseLink}`,
      `   - commands: ${commands.map((command) => String(command.command || '').trim()).filter(Boolean).join(' | ') || 'none'}`,
      `   - evidenceDocs: ${evidenceDocs.map((doc) => String(doc.path || doc.label || '').trim()).filter(Boolean).join(' | ') || 'none'}`,
      `   - requiredProofs: ${requiredProofs.length ? requiredProofs.join(' | ') : 'none'}`,
    ].join('\n');
  });
}

function getReleaseProviderLiveStatus(provider = '', releaseStatus = state.releaseStatus) {
  const normalizedProvider = String(provider || '').trim();
  if (!normalizedProvider) {
    return '';
  }
  const liveValidation = Array.isArray(releaseStatus?.liveValidation)
    ? releaseStatus.liveValidation
    : [];
  const entry = liveValidation.find((item) => String(item?.provider || '').trim() === normalizedProvider);
  return String(entry?.status || '').trim();
}

function getReleaseProviderSpecificEvidenceDoc(provider = '') {
  const normalizedProvider = String(provider || '').trim();
  const providerDocMap = {
    anthropic: {
      label: 'Target Anthropic provider account',
      path: 'docs/target-anthropic-provider-account-v1.md',
    },
    hermes: {
      label: 'Target Hermes provider architecture',
      path: 'docs/target-hermes-provider-architecture-v1.md',
    },
    local: {
      label: 'Target local provider architecture',
      path: 'docs/target-local-provider-architecture-v1.md',
    },
    openai: {
      label: 'Target OpenAI provider account',
      path: 'docs/target-openai-provider-account-v1.md',
    },
  };
  return providerDocMap[normalizedProvider] || null;
}

function buildReleaseProviderReadinessUrl(provider = '') {
  const normalizedProvider = String(provider || '').trim();
  return `${window.location.origin}${buildUiStateUrl({
    detailTab: 'release',
    releaseBlockerCategoryFilter: '',
    releaseBlockerOwnerFilter: '',
    releaseBlockerProviderFilter: '',
    releaseFocusedBlockerId: '',
    releaseFocusedProductionBlockerIndex: '',
    releaseFocusedProvider: normalizedProvider,
    releaseFocusedHistoryId: '',
    releaseHistoryOutcome: '',
    releaseHistoryProvider: '',
    releaseHistoryScope: '',
  })}`;
}

function formatReleaseProviderReadinessEvidenceDocLines(docs = []) {
  return docs.map((doc, index) => {
    const encodedPath = encodeURIComponent(doc.path);
    return [
      `${index + 1}. ${doc.label}`,
      `   - path: ${doc.path}`,
      `   - link: ${getAbsoluteReleaseUrl(`/api/execution-v1/release-doc?path=${encodedPath}`)}`,
    ].join('\n');
  });
}

function getReleaseProviderReadinessEvidenceDocs(provider = '') {
  const docs = [
    {
      label: 'Production provider readiness',
      path: 'docs/production-provider-readiness-v1.md',
    },
    {
      label: 'Target provider evidence intake',
      path: 'docs/target-provider-evidence-intake-v1.md',
    },
    {
      label: 'Target provider operations',
      path: 'docs/target-provider-operations-v1.md',
    },
  ];
  const providerSpecificDoc = getReleaseProviderSpecificEvidenceDoc(provider);
  if (providerSpecificDoc) {
    docs.push(providerSpecificDoc);
  }
  return docs;
}

function buildReleaseProviderReadinessEvidenceDocLines(provider = '') {
  return formatReleaseProviderReadinessEvidenceDocLines(getReleaseProviderReadinessEvidenceDocs(provider));
}

function buildReleaseProviderReadinessPackageText({
  provider = '',
  releaseStatus = state.releaseStatus,
} = {}) {
  const entries = getReleaseProviderReadinessEntries({ provider, releaseStatus });
  if (!entries.length) {
    return '';
  }

  const normalizedProvider = String(provider || '').trim();
  const summary = releaseStatus?.summary || {};
  const releaseReadiness = releaseStatus?.releaseReadiness || {};
  const packageScope = normalizedProvider || 'all providers';
  const releaseLink = buildReleaseProviderReadinessUrl(normalizedProvider);
  const productionProviderReadinessDoc = getAbsoluteReleaseUrl(
    '/api/execution-v1/release-doc?path=docs%2Fproduction-provider-readiness-v1.md',
  );
  const releaseReadinessDoc = getAbsoluteReleaseUrl(
    '/api/execution-v1/release-doc?path=docs%2Frelease-readiness-v1.md',
  );
  const providerLines = entries.map((item, index) => {
    const itemProvider = String(item.provider || '').trim();
    const preflight = state.releasePreflightResults?.[itemProvider] || null;
    const preflightStatus = String(preflight?.status || 'not-run').trim();
    const liveStatus = getReleaseProviderLiveStatus(itemProvider, releaseStatus) || 'not archived';
    const liveCommand = getProviderLiveCommand(item, preflight);
    const linkedBlockers = getReleaseProviderBlockerActions({ provider: itemProvider, releaseStatus });
    const linkedBlockerIds = linkedBlockers.map((action) => String(action.id || '').trim()).filter(Boolean);
    const linkedSharedBlockerIds = linkedBlockers
      .filter((action) => isReleaseSharedProviderBlockerAction(action))
      .map((action) => String(action.id || '').trim())
      .filter(Boolean);
    const linkedClosureVerificationIds = Array.isArray(item.blockerClosureVerification?.closureVerificationIds)
      ? item.blockerClosureVerification.closureVerificationIds
      : linkedBlockers
        .map((action) => String(getReleaseBlockerClosureVerification(action).id || '').trim())
        .filter(Boolean);
    const linkedRequiredProofCount = Number.isFinite(Number(item.blockerClosureVerification?.requiredProofCount))
      ? Number(item.blockerClosureVerification.requiredProofCount)
      : new Set(linkedBlockers.flatMap((action) => getReleaseBlockerRequiredProofs(action))).size;
    return [
      `${index + 1}. ${item.label || itemProvider}`,
      `   - provider: ${itemProvider}`,
      `   - envKey: ${item.envKey || '-'}`,
      `   - envReady: ${String(Boolean(item.ready))}`,
      `   - readinessStatus: ${item.status || 'unknown'}`,
      `   - preflightStatus: ${preflightStatus}`,
      `   - archivedLiveStatus: ${liveStatus}`,
      `   - linkedCurrentBlockers: ${linkedBlockerIds.length ? linkedBlockerIds.join(', ') : 'none'}`,
      `   - linkedSharedBlockers: ${linkedSharedBlockerIds.length ? linkedSharedBlockerIds.join(', ') : 'none'}`,
      `   - linkedClosureVerifications: ${linkedClosureVerificationIds.length ? linkedClosureVerificationIds.join(', ') : 'none'}`,
      `   - linkedRequiredProofCount: ${String(linkedRequiredProofCount)}`,
      `   - preflightCommand: ${item.preflightCommand || `npm run preflight:execution-v1:${itemProvider}`}`,
      `   - liveCommand: ${liveCommand || item.command || '-'}`,
      `   - evidenceCommand: ${item.evidenceCommand || `node scripts/build-execution-v1-evidence.mjs --live-${itemProvider}`}`,
    ].join('\n');
  });
  const providerSpecificCommands = entries.flatMap((item) => {
    const itemProvider = String(item.provider || '').trim();
    const preflight = state.releasePreflightResults?.[itemProvider] || null;
    const liveCommand = getProviderLiveCommand(item, preflight);
    return [
      `- ${item.label || itemProvider} preflight: ${item.preflightCommand || `npm run preflight:execution-v1:${itemProvider}`}`,
      `- ${item.label || itemProvider} live validation: ${liveCommand || item.command || '-'}`,
      `- ${item.label || itemProvider} evidence refresh: ${item.evidenceCommand || `node scripts/build-execution-v1-evidence.mjs --live-${itemProvider}`}`,
    ];
  });
  const evidenceDocLines = normalizedProvider
    ? buildReleaseProviderReadinessEvidenceDocLines(normalizedProvider)
    : formatReleaseProviderReadinessEvidenceDocLines([
        ...getReleaseProviderReadinessEvidenceDocs('openai'),
        getReleaseProviderSpecificEvidenceDoc('anthropic'),
        getReleaseProviderSpecificEvidenceDoc('local'),
        getReleaseProviderSpecificEvidenceDoc('hermes'),
      ].filter(Boolean));
  const linkedProviderBlockers = getUniqueReleaseProviderBlockerActions(
    entries.flatMap((item) =>
      getReleaseProviderBlockerActions({
        provider: String(item.provider || '').trim(),
        releaseStatus,
      }),
    ),
  );
  const linkedProviderBlockerLines = buildReleaseProviderBlockerPackageLines(linkedProviderBlockers);

  return [
    'Provider readiness handoff package',
    '',
    'Scope:',
    `- provider: ${packageScope}`,
    `- productionReadyStatus: ${summary.productionReadyStatus || releaseReadiness.productionReadyStatus || 'not tracked'}`,
    `- productionReadyBlocked: ${String(Boolean(summary.productionReadyBlocked ?? releaseReadiness.productionReadyBlocked ?? true))}`,
    `- productionBlockerCount: ${summary.productionBlockerCount ?? 'not tracked'}`,
    `- productionReadyStopReason: ${summary.productionReadyStopReason || releaseReadiness.productionReadyStopReason || 'not recorded'}`,
    `- releaseLink: ${releaseLink}`,
    `- productionProviderReadinessDoc: ${productionProviderReadinessDoc}`,
    `- releaseReadinessDoc: ${releaseReadinessDoc}`,
    '',
    'Provider readiness matrix:',
    ...providerLines,
    '',
    'Linked provider blockers:',
    ...linkedProviderBlockerLines,
    '',
    'Commands:',
    '- Aggregate preflight: npm run preflight:execution-v1:all',
    '- Provider readiness rehearsal: npm run rehearsal:production-provider-readiness',
    '- Provider readiness smoke: npm run smoke:production-provider-readiness',
    ...providerSpecificCommands,
    '- Target provider evidence intake smoke: npm run smoke:target-provider-evidence-intake',
    '- Target provider operations smoke: npm run smoke:target-provider-operations',
    '- Artifact refresh after accepted live proof: npm run refresh:execution-v1-artifacts',
    '- Production readiness gate: npm run smoke:production-readiness-gate',
    '- Release artifact hygiene: npm run smoke:release-artifact-hygiene',
    '- Execution v1 status: npm run smoke:execution-v1-status',
    '',
    'Evidence docs:',
    ...evidenceDocLines,
    '',
    'Closure rules:',
    '- Provider env or account remediation must be completed outside this UI package before live validation can pass.',
    '- Target provider evidence intake must include provider evidence intake proof with provider id, inclusion decision, account owner, customer/workspace approval, approved target boundary, target environment name, release label, source commit, stop-condition id, evidence owner, reviewer, and decision owner; account or architecture approval proof; target secret injection proof; target-boundary live validation proof; quota and cost guard proof; model and endpoint pinning proof; fallback route proof; provider blocker closure verification proof; and release artifact reference proof.',
    '- Target provider operations must include provider operations proof with provider inventory, included provider list, provider owner, account or architecture record, customer/workspace approval, operating decision, and residual risk owner; provider fallback runtime audit proof with fallback policy and stop reason; recoverable-provider-failure-only stop condition proof; telemetry proof; incident triage proof; data and transcript handling proof; remediation and renewal review proof; evidence retention proof; and provider failure containment proof.',
    '- Regenerate execution-v1 artifacts after intentional live-provider proof or source-of-record changes.',
    '- Keep productionReadyClaim=false while any provider or target-environment stop-condition remains open.',
  ].join('\n');
}

function getReleaseBlockerSliceSummary({
  blockerActions = getFilteredReleaseCurrentOpenBlockerActions(),
  totalActions = getReleaseCurrentOpenBlockerActions(),
} = {}) {
  const visibleActions = Array.isArray(blockerActions) ? blockerActions : [];
  const allActions = Array.isArray(totalActions) ? totalActions : [];
  const evidenceDocKeys = new Set();
  const requiredProofKeys = new Set();
  const commandCount = visibleActions.reduce((total, item) => {
    const commands = getReleaseBlockerRequiredCommands(item);
    return total + commands.filter((command) => String(command.command || '').trim()).length;
  }, 0);
  let closureVerificationCount = 0;
  let productionReadyBlockedCount = 0;
  let targetBoundaryRequiredCount = 0;
  visibleActions.forEach((item) => {
    const closureVerification = getReleaseBlockerClosureVerification(item);
    if (closureVerification.id || item.closureVerification) {
      closureVerificationCount += 1;
    }
    if (closureVerification.targetBoundaryRequired === true) {
      targetBoundaryRequiredCount += 1;
    }
    if (closureVerification.productionReadyClaimAllowed === false) {
      productionReadyBlockedCount += 1;
    }
    const requiredProofs = getReleaseBlockerRequiredProofs(item);
    requiredProofs.forEach((proof) => {
      const proofText = String(proof || '').trim();
      if (proofText) {
        requiredProofKeys.add(proofText);
      }
    });
    const evidenceDocs = getReleaseBlockerRequiredEvidenceDocs(item);
    evidenceDocs.forEach((doc) => {
      const docLabel = String(doc.label || doc.path || 'evidence doc').trim();
      const docPath = String(doc.path || '').trim();
      const docHref = getAbsoluteReleaseUrl(doc.href || '');
      const docKey = docHref || docPath || docLabel;
      if (docKey) {
        evidenceDocKeys.add(docKey);
      }
    });
  });
  const topVisibleAction = visibleActions[0] || null;

  return {
    closureVerificationCount,
    commandCount,
    evidenceDocCount: evidenceDocKeys.size,
    productionReadyBlockedCount,
    requiredProofCount: requiredProofKeys.size,
    targetBoundaryRequiredCount,
    topVisibleBlockerId: String(topVisibleAction?.id || '').trim(),
    topVisibleBlockerLabel: String(topVisibleAction?.blocker || topVisibleAction?.stopReason || '').trim(),
    totalCount: allActions.length,
    visibleCount: visibleActions.length,
  };
}

function getReleaseSharedProviderOperationsScopeReason({
  includeShared = true,
  provider = state.releaseBlockerProviderFilter,
} = {}) {
  const normalizedProvider = String(provider || '').trim();
  if (includeShared === false && normalizedProvider) {
    return `excluded for provider-only ${normalizedProvider} handoff; handle shared provider-operations evidence separately`;
  }
  if (includeShared === false) {
    return 'excluded for scoped handoff; handle shared provider-operations evidence separately';
  }
  if (normalizedProvider) {
    return `included with provider ${normalizedProvider} handoff scope`;
  }
  return 'included for full release blocker handoff scope';
}

function getReleaseSharedProviderOperationsScopeAudit({
  totalActions = getReleaseCurrentOpenBlockerActions(),
  category = state.releaseBlockerCategoryFilter,
  includeShared = true,
  owner = state.releaseBlockerOwnerFilter,
  provider = state.releaseBlockerProviderFilter,
} = {}) {
  const allActions = Array.isArray(totalActions) ? totalActions : [];
  const scopedActions = allActions.filter((action) =>
    isReleaseBlockerActionVisibleForFilter(action, {
      category,
      includeShared: true,
      owner,
      provider,
    }),
  );
  const visibleActions = allActions.filter((action) =>
    isReleaseBlockerActionVisibleForFilter(action, {
      category,
      includeShared,
      owner,
      provider,
    }),
  );
  const excludedActions = includeShared === false
    ? scopedActions.filter((action) => isReleaseSharedProviderBlockerAction(action))
    : [];

  return {
    excludedCount: excludedActions.length,
    excludedIds: excludedActions.map((action) => String(action.id || '').trim()).filter(Boolean),
    includedCount: visibleActions.filter((action) => isReleaseSharedProviderBlockerAction(action)).length,
  };
}

function buildReleaseSharedProviderOperationsScopeAuditLines(options = {}) {
  const scopeAudit = getReleaseSharedProviderOperationsScopeAudit(options);
  return [
    `- sharedProviderOperationsIncludedCount: ${scopeAudit.includedCount}`,
    `- sharedProviderOperationsExcludedCount: ${scopeAudit.excludedCount}`,
    `- sharedProviderOperationsExcludedIds: ${scopeAudit.excludedIds.join(', ') || 'none'}`,
  ];
}

function buildReleaseBlockerSliceSummaryText({
  blockerActions = getFilteredReleaseCurrentOpenBlockerActions(),
  totalActions = getReleaseCurrentOpenBlockerActions(),
  category = state.releaseBlockerCategoryFilter,
  includeShared = true,
  owner = state.releaseBlockerOwnerFilter,
  provider = state.releaseBlockerProviderFilter,
} = {}) {
  const visibleActions = Array.isArray(blockerActions) ? blockerActions : [];
  const allActions = Array.isArray(totalActions) ? totalActions : [];
  if (!allActions.length) {
    return '';
  }

  const normalizedCategory = String(category || '').trim();
  const normalizedOwner = String(owner || '').trim();
  const normalizedProvider = String(provider || '').trim();
  const sliceSummary = getReleaseBlockerSliceSummary({
    blockerActions: visibleActions,
    totalActions: allActions,
  });
  const sliceLink = buildReleaseBlockerSliceUrl({
    category: normalizedCategory,
    includeShared,
    owner: normalizedOwner,
    provider: normalizedProvider,
  });
  const apiLink = buildReleaseBlockerApiUrl({
    category: normalizedCategory,
    includeShared,
    owner: normalizedOwner,
    provider: normalizedProvider,
  });
  const topBlockerLabel = sliceSummary.topVisibleBlockerLabel
    ? `${sliceSummary.topVisibleBlockerId || 'unknown'}: ${sliceSummary.topVisibleBlockerLabel}`
    : 'none';
  const lines = [
    'Release blocker slice summary',
    `- category: ${normalizedCategory || 'all'}`,
    `- owner: ${normalizedOwner || 'all'}`,
    `- provider: ${normalizedProvider || 'all'}`,
    `- includeSharedProviderOperations: ${String(includeShared !== false)}`,
    `- sharedProviderOperationsScope: ${getReleaseSharedProviderOperationsScopeReason({ includeShared, provider: normalizedProvider })}`,
    ...buildReleaseSharedProviderOperationsScopeAuditLines({
      totalActions: allActions,
      category: normalizedCategory,
      includeShared,
      owner: normalizedOwner,
      provider: normalizedProvider,
    }),
    `- visibleBlockers: ${sliceSummary.visibleCount}/${sliceSummary.totalCount}`,
    `- closureVerificationCount: ${sliceSummary.closureVerificationCount}`,
    `- targetBoundaryRequired: ${sliceSummary.targetBoundaryRequiredCount}/${sliceSummary.visibleCount}`,
    `- productionReadyClaimBlocked: ${sliceSummary.productionReadyBlockedCount}/${sliceSummary.visibleCount}`,
    `- commandCount: ${sliceSummary.commandCount}`,
    `- evidenceDocCount: ${sliceSummary.evidenceDocCount}`,
    `- requiredProofCount: ${sliceSummary.requiredProofCount}`,
    `- topVisibleBlocker: ${topBlockerLabel}`,
    `- releaseLink: ${sliceLink}`,
    `- apiLink: ${apiLink}`,
  ];

  return `${lines.join('\n')}\n`;
}

function getReleaseBlockerClosureVerification(blockerAction = {}) {
  return blockerAction && typeof blockerAction.closureVerification === 'object' && blockerAction.closureVerification
    ? blockerAction.closureVerification
    : {};
}

function getReleaseBlockerRequiredCommands(blockerAction = {}) {
  const closureVerification = getReleaseBlockerClosureVerification(blockerAction);
  if (Array.isArray(closureVerification.requiredCommands)) {
    return closureVerification.requiredCommands;
  }
  return Array.isArray(blockerAction.commands) ? blockerAction.commands : [];
}

function getReleaseBlockerRequiredEvidenceDocs(blockerAction = {}) {
  const closureVerification = getReleaseBlockerClosureVerification(blockerAction);
  if (Array.isArray(closureVerification.requiredEvidenceDocs)) {
    return closureVerification.requiredEvidenceDocs;
  }
  return Array.isArray(blockerAction.evidenceDocs) ? blockerAction.evidenceDocs : [];
}

function getReleaseBlockerRequiredProofs(blockerAction = {}) {
  const closureVerification = getReleaseBlockerClosureVerification(blockerAction);
  return Array.isArray(closureVerification.requiredProofs) ? closureVerification.requiredProofs : [];
}

function buildReleaseBlockerHandoffText(blockerAction = null) {
  const actionId = String(blockerAction?.id || '').trim();
  if (!blockerAction || !actionId) {
    return '';
  }

  const blockerLink = `${window.location.origin}${buildUiStateUrl({
    detailTab: 'release',
    releaseFocusedBlockerId: actionId,
    releaseFocusedProductionBlockerIndex: '',
    releaseFocusedProvider: '',
    releaseFocusedHistoryId: '',
    releaseHistoryOutcome: '',
    releaseHistoryProvider: '',
    releaseHistoryScope: '',
  })}`;
  const evidenceDocs = Array.isArray(blockerAction.evidenceDocs) ? blockerAction.evidenceDocs : [];
  const commands = Array.isArray(blockerAction.commands) ? blockerAction.commands : [];
  const lines = [
    'Release blocker handoff',
    `- blocker: ${String(blockerAction.blocker || blockerAction.stopReason || 'current open blocker').trim()}`,
    `- id: ${actionId}`,
    `- category: ${String(blockerAction.category || 'stop-condition').trim()}`,
    `- owner: ${String(blockerAction.owner || 'release-owner').trim()}`,
    `- status: ${String(blockerAction.status || 'blocked').trim()}`,
    `- stopReason: ${String(blockerAction.stopReason || blockerAction.blocker || '').trim()}`,
    `- nextEvidence: ${String(blockerAction.nextEvidence || '').trim()}`,
    `- releaseLink: ${blockerLink}`,
    '',
    'Evidence docs:',
    ...(
      evidenceDocs.length
        ? evidenceDocs.map((doc) => {
            const docLabel = String(doc.label || doc.path || 'evidence doc').trim();
            const docPath = String(doc.path || '').trim();
            const docHref = getAbsoluteReleaseUrl(doc.href || '');
            const availability = doc.exists === false ? 'missing' : 'available';
            return `- ${docLabel}: ${docPath}${docHref ? ` (${docHref})` : ''} [${availability}]`;
          })
        : ['- none']
    ),
    '',
    'Commands:',
    ...(
      commands.length
        ? commands.map((command) => {
            const commandLabel = String(command.label || 'command').trim();
            const commandValue = String(command.command || '').trim();
            return `- ${commandLabel}: ${commandValue}`;
          })
        : ['- none']
    ),
  ];

  return `${lines.join('\n')}\n`;
}

function buildReleaseBlockerClosureChecklistText(blockerAction = null) {
  const actionId = String(blockerAction?.id || '').trim();
  if (!blockerAction || !actionId) {
    return '';
  }

  const blockerLabel = String(blockerAction.blocker || blockerAction.stopReason || 'current open blocker').trim();
  const closureVerification = blockerAction.closureVerification || {};
  const nextEvidence = String(closureVerification.requiredClosingEvidence || blockerAction.nextEvidence || '').trim();
  const evidenceDocs = Array.isArray(closureVerification.requiredEvidenceDocs)
    ? closureVerification.requiredEvidenceDocs
    : Array.isArray(blockerAction.evidenceDocs)
      ? blockerAction.evidenceDocs
      : [];
  const commands = Array.isArray(closureVerification.requiredCommands)
    ? closureVerification.requiredCommands
    : Array.isArray(blockerAction.commands)
      ? blockerAction.commands
      : [];
  const closureRules = Array.isArray(closureVerification.closureRules)
    ? closureVerification.closureRules
    : [];
  const requiredProofs = Array.isArray(closureVerification.requiredProofs)
    ? closureVerification.requiredProofs
    : [];
  const requiredDecisionFields = Array.isArray(closureVerification.requiredDecisionFields)
    ? closureVerification.requiredDecisionFields
    : [];
  const forbiddenEvidence = Array.isArray(closureVerification.forbiddenEvidence)
    ? closureVerification.forbiddenEvidence
    : [];
  const blockerLink = `${window.location.origin}${buildUiStateUrl({
    detailTab: 'release',
    releaseFocusedBlockerId: actionId,
    releaseFocusedProductionBlockerIndex: '',
    releaseFocusedProvider: '',
    releaseFocusedHistoryId: '',
    releaseHistoryOutcome: '',
    releaseHistoryProvider: '',
    releaseHistoryScope: '',
  })}`;
  const lines = [
    'Release blocker closure checklist',
    `- blocker: ${blockerLabel}`,
    `- id: ${actionId}`,
    `- category: ${String(blockerAction.category || 'stop-condition').trim()}`,
    `- owner: ${String(blockerAction.owner || 'release-owner').trim()}`,
    `- status: ${String(blockerAction.status || 'blocked').trim()}`,
    `- stopReason: ${String(blockerAction.stopReason || blockerLabel).trim()}`,
    `- nextEvidence: ${nextEvidence || 'not recorded'}`,
    `- closureVerification: ${closureVerification.id ? closureVerification.id : 'not provided'}`,
    `- targetBoundaryRequired: ${String(Boolean(closureVerification.targetBoundaryRequired ?? true))}`,
    `- sameBoundaryRequired: ${String(Boolean(closureVerification.sameBoundaryRequired ?? true))}`,
    `- productionReadyClaimAllowed: ${String(Boolean(closureVerification.productionReadyClaimAllowed))}`,
    `- defaultDisposition: ${String(closureVerification.defaultDisposition || 'keep-blocked')}`,
    `- releaseLink: ${blockerLink}`,
    '',
    'Closure requirements:',
    `1. Capture closing evidence for: ${nextEvidence || blockerLabel}`,
    '2. Update or attach every evidence doc listed below before changing the release label.',
    '3. Run the blocker-specific commands listed below and keep command output with the evidence packet.',
    '4. Regenerate execution-v1 artifacts if live proof or any release source-of-record changes.',
    '5. Keep productionReadyClaim=false until production readiness and artifact hygiene gates pass with no stop-condition.',
    '',
    'Closure rules:',
    ...(
      closureRules.length
        ? closureRules.map((rule, index) => `${index + 1}. ${String(rule || '').trim()}`)
        : ['- target-boundary evidence and reviewer decision are required']
    ),
    '',
    'Required proofs:',
    ...(
      requiredProofs.length
        ? requiredProofs.map((proof, index) => `${index + 1}. ${String(proof || '').trim()}`)
        : ['- same-boundary target evidence packet proof']
    ),
    '',
    'Evidence docs:',
    ...(
      evidenceDocs.length
        ? evidenceDocs.map((doc, index) => {
            const docLabel = String(doc.label || doc.path || 'evidence doc').trim();
            const docPath = String(doc.path || '').trim();
            const docHref = getAbsoluteReleaseUrl(doc.href || '');
            const availability = doc.exists === false ? 'missing' : 'available';
            return [
              `${index + 1}. ${docLabel}`,
              `   - path: ${docPath || 'path м—ҶмқҢ'}`,
              `   - link: ${docHref || 'link м—ҶмқҢ'}`,
              `   - availability: ${availability}`,
            ].join('\n');
          })
        : ['- none']
    ),
    '',
    'Commands:',
    ...(
      commands.length
        ? commands.map((command, index) => {
            const commandLabel = String(command.label || 'command').trim();
            const commandValue = String(command.command || '').trim();
            return `${index + 1}. ${commandLabel}: ${commandValue || 'command м—ҶмқҢ'}`;
      })
        : ['- none']
    ),
    '',
    'Decision fields:',
    ...(
      requiredDecisionFields.length
        ? requiredDecisionFields.map((field) => `- ${String(field || '').trim()}`)
        : ['- decisionOwner', '- evidenceOwner', '- reviewer', '- reviewDate']
    ),
    '',
    'Forbidden evidence:',
    ...(
      forbiddenEvidence.length
        ? forbiddenEvidence.map((item) => `- ${String(item || '').trim()}`)
        : ['- raw API keys or tokens', '- customer personal data']
    ),
    '',
    'Final verification:',
    '- Artifact refresh: npm run refresh:execution-v1-artifacts',
    '- Production readiness gate: npm run smoke:production-readiness-gate',
    '- Release artifact hygiene: npm run smoke:release-artifact-hygiene',
    '- Execution v1 status: npm run smoke:execution-v1-status',
  ];

  return `${lines.join('\n')}\n`;
}

function buildReleaseBlockerPackageText(blockerAction = null) {
  const actionId = String(blockerAction?.id || '').trim();
  if (!blockerAction || !actionId) {
    return '';
  }

  const blockerLabel = String(blockerAction.blocker || blockerAction.stopReason || 'current open blocker').trim();
  const evidenceDocs = Array.isArray(blockerAction.evidenceDocs) ? blockerAction.evidenceDocs : [];
  const commands = Array.isArray(blockerAction.commands) ? blockerAction.commands : [];
  const commandSection = [
    'Release blocker commands',
    `- blocker: ${blockerLabel}`,
    `- id: ${actionId}`,
    `- commandCount: ${commands.length}`,
    '',
    'Commands:',
    ...(
      commands.length
        ? commands.map((command, index) => {
            const commandLabel = String(command.label || 'command').trim();
            const commandValue = String(command.command || '').trim();
            return `${index + 1}. ${commandLabel}: ${commandValue || 'command м—ҶмқҢ'}`;
          })
        : ['- none']
    ),
  ].join('\n');
  const evidenceSection = [
    'Release blocker evidence',
    `- blocker: ${blockerLabel}`,
    `- id: ${actionId}`,
    `- evidenceDocCount: ${evidenceDocs.length}`,
    '',
    'Evidence docs:',
    ...(
      evidenceDocs.length
        ? evidenceDocs.map((doc, index) => {
            const docLabel = String(doc.label || doc.path || 'evidence doc').trim();
            const docPath = String(doc.path || '').trim();
            const docHref = getAbsoluteReleaseUrl(doc.href || '');
            const availability = doc.exists === false ? 'missing' : 'available';
            return [
              `${index + 1}. ${docLabel}`,
              `   - path: ${docPath || 'path м—ҶмқҢ'}`,
              `   - link: ${docHref || 'link м—ҶмқҢ'}`,
              `   - availability: ${availability}`,
            ].join('\n');
          })
        : ['- none']
    ),
  ].join('\n');
  const sections = [
    buildReleaseBlockerHandoffText(blockerAction),
    buildReleaseBlockerClosureChecklistText(blockerAction),
    commandSection,
    evidenceSection,
  ]
    .map((section) => String(section || '').trim())
    .filter(Boolean);

  if (!sections.length) {
    return '';
  }

  return `Release blocker package\n\n${sections.join('\n\n')}\n`;
}

function buildReleaseBlockerSliceHandoffText({
  blockerActions = getFilteredReleaseCurrentOpenBlockerActions(),
  totalActions = getReleaseCurrentOpenBlockerActions(),
  category = state.releaseBlockerCategoryFilter,
  owner = state.releaseBlockerOwnerFilter,
  provider = state.releaseBlockerProviderFilter,
} = {}) {
  const visibleActions = Array.isArray(blockerActions) ? blockerActions : [];
  const allActions = Array.isArray(totalActions) ? totalActions : [];
  if (!allActions.length) {
    return '';
  }

  const normalizedCategory = String(category || '').trim();
  const normalizedOwner = String(owner || '').trim();
  const normalizedProvider = String(provider || '').trim();
  const sliceLink = buildReleaseBlockerSliceUrl({
    category: normalizedCategory,
    includeShared,
    owner: normalizedOwner,
    provider: normalizedProvider,
  });
  const topVisibleAction = visibleActions[0] || null;
  const formatEvidenceDoc = (doc = {}) => {
    const docLabel = String(doc.label || doc.path || 'evidence doc').trim();
    const docPath = String(doc.path || '').trim();
    const docHref = getAbsoluteReleaseUrl(doc.href || '');
    const availability = doc.exists === false ? 'missing' : 'available';
    return `${docLabel}: ${docPath || 'path м—ҶмқҢ'}${docHref ? ` (${docHref})` : ''} [${availability}]`;
  };
  const formatCommand = (command = {}) => {
    const commandLabel = String(command.label || 'command').trim();
    const commandValue = String(command.command || '').trim();
    return `${commandLabel}: ${commandValue || 'command м—ҶмқҢ'}`;
  };
  const blockerLines = visibleActions.length
    ? visibleActions.flatMap((item, index) => {
        const actionId = String(item.id || '').trim();
        const closureVerification = getReleaseBlockerClosureVerification(item);
        const evidenceDocs = getReleaseBlockerRequiredEvidenceDocs(item);
        const commands = getReleaseBlockerRequiredCommands(item);
        const requiredProofs = getReleaseBlockerRequiredProofs(item);
        return [
          `${index + 1}. ${String(item.blocker || item.stopReason || 'current open blocker').trim()}`,
          `   - id: ${actionId || 'unknown'}`,
          `   - category: ${String(item.category || 'stop-condition').trim()}`,
          `   - owner: ${String(item.owner || 'release-owner').trim()}`,
          `   - status: ${String(item.status || 'blocked').trim()}`,
          `   - stopReason: ${String(item.stopReason || item.blocker || '').trim()}`,
          `   - nextEvidence: ${String(item.nextEvidence || '').trim()}`,
          `   - closureVerification: ${String(closureVerification.id || 'not provided').trim()}`,
          `   - targetBoundaryRequired: ${String(Boolean(closureVerification.targetBoundaryRequired ?? true))}`,
          `   - requiredProofCount: ${requiredProofs.length}`,
          `   - evidenceDocs: ${evidenceDocs.length ? evidenceDocs.map(formatEvidenceDoc).join('; ') : 'none'}`,
          `   - commands: ${commands.length ? commands.map(formatCommand).join('; ') : 'none'}`,
        ];
      })
    : ['- none'];
  const lines = [
    'Release blocker slice handoff',
    `- category: ${normalizedCategory || 'all'}`,
    `- owner: ${normalizedOwner || 'all'}`,
    `- provider: ${normalizedProvider || 'all'}`,
    `- visibleBlockers: ${visibleActions.length}/${allActions.length}`,
    `- releaseLink: ${sliceLink}`,
    `- topVisibleBlocker: ${topVisibleAction ? `${String(topVisibleAction.id || 'unknown').trim()}: ${String(topVisibleAction.blocker || topVisibleAction.stopReason || 'current open blocker').trim()}` : 'none'}`,
    '',
    'Blockers:',
    ...blockerLines,
  ];

  return `${lines.join('\n')}\n`;
}

