                                                        actionLabel: `нҳ„мһ¬ handoff summary line ліөмӮ¬: ${handoffPreviewArtifact.label || handoffPreviewArtifact.id || handoffPreviewArtifact.path || 'artifact'} ${detail.label || detail.key || 'detail'}`,
                                                        artifactId: handoffPreviewArtifact.id || '',
                                                        attributes: `data-release-handoff-current-preview-structured-summary-detail-copy="${escapeHtml(detail.key || '')}"`,
                                                        buttonText: 'нҳ„мһ¬ line ліөмӮ¬',
                                                        copiedText: 'нҳ„мһ¬ line ліөмӮ¬лҗЁ',
