                                              copiedText: 'нҳ„мһ¬ мҡ”м•Ҫ ліөмӮ¬лҗЁ',
                                              successNotice: `${handoffPreviewArtifact.label || 'нҳ„мһ¬ handoff summary'} overview lineмқ„ ліөмӮ¬н–ҲмҠөлӢҲлӢӨ.`,
